function seedStoredCard(seed, deckId){
  return {
    ...seed,
    id:uid(), deckId,
    acceptedAnswers:[...(seed.acceptedAnswers||[])],
    tags:[...(seed.tags||[])], collocations:[...(seed.collocations||[])],
    relatedExpressions:[...(seed.relatedExpressions||[])], wordFamily:[...(seed.wordFamily||[])],
    extraExamples:[...(seed.extraExamples||[])],
    source:seed.source||"WordLoop 200 词库", difficulty:seed.difficulty||1, isSuspended:false,
    createdAt:nowISO(), updatedAt:nowISO()
  };
}
function cardMatchKey(c){ return `${(c.word||"").toLowerCase()}|${(c.sentenceEn||c.targetEnglish||"").toLowerCase()}`; }
function migrateToV2(force=false){
  const previousVersion=Number(state.version||1);
  state.decks=state.decks||[]; state.cards=state.cards||[]; state.reviewStates=state.reviewStates||[]; state.reviewLogs=state.reviewLogs||[]; state.settings=state.settings||{}; state.ui=state.ui||{};
  const deckByName=new Map(state.decks.map(d=>[d.name,d]));
  const ensureDeck=(name)=>{ if(deckByName.has(name)) return deckByName.get(name); const d={id:uid(),name,description:"WordLoop 200 词库",color:"#6d5dfc",createdAt:nowISO(),updatedAt:nowISO()}; state.decks.push(d);deckByName.set(name,d);return d; };
  const existingKeys=new Map(state.cards.map(c=>[cardMatchKey(c),c]));
  expandedSeedCards.forEach((seed,index)=>{
    const deck=ensureDeck(seed.deck); const match=state.cards.find(c=>c.seedKey===seed.seedKey)||existingKeys.get(cardMatchKey(seed));
    if(match){
      match.seedKey=seed.seedKey;
      ["pronunciation","answerPronunciation","definitionZh","usageNotes"].forEach(k=>{if(!match[k])match[k]=seed[k]||""});
      ["collocations","relatedExpressions","wordFamily","extraExamples"].forEach(k=>{if(!Array.isArray(match[k])||!match[k].length)match[k]=seed[k]||[]});
      if(!Array.isArray(match.acceptedAnswers)||!match.acceptedAnswers.length)match.acceptedAnswers=seed.acceptedAnswers||[];
    }else{
      const c=seedStoredCard(seed,deck.id); state.cards.push(c); existingKeys.set(cardMatchKey(c),c);
      state.reviewStates.push({cardId:c.id,status:"new",level:0,intervalDays:0,consecutiveCorrect:0,totalCorrect:0,totalWrong:0,lapses:0,dueAt:index<10?nowISO():addDays(new Date(),1+(index%20)),lastReviewedAt:null,averageResponseTime:0});
    }
  });
  state.cards.forEach(c=>{
    c.collocations=Array.isArray(c.collocations)?c.collocations:[];
    c.relatedExpressions=Array.isArray(c.relatedExpressions)?c.relatedExpressions:[];
    c.wordFamily=Array.isArray(c.wordFamily)?c.wordFamily:[];
    c.extraExamples=Array.isArray(c.extraExamples)?c.extraExamples:[];
    c.acceptedAnswers=Array.isArray(c.acceptedAnswers)?c.acceptedAnswers:[];
  });
  if(previousVersion<2||force){
    state.settings.autoAdvance=false;
    state.settings.autoAdvanceDelay=10000;
    state.settings.autoPlayAudio=true;
    state.settings.showLearningDetails=true;
    state.settings.hintSequence="audio-ipa-answer";
  }
  state.version=Math.max(2,previousVersion); save();
}
migrateToV2();

resetData=function(){
  state=initialState(); state.version=1; practiceSession=null; migrateToV2(true); save(); route(); toast("已恢复 200 张示例卡片");
};

function uniqueAnswers(card){
  const target=card.type==="cloze"?card.clozeAnswer:card.targetEnglish;
  const all=[target,...(card.acceptedAnswers||[])].filter(Boolean);
  const seen=new Set(); return all.filter(a=>{const k=normalizeAnswer(a);if(seen.has(k))return false;seen.add(k);return true;});
}
function targetHintText(card){ return card.type==="cloze"?(card.clozeAnswer||card.word):(card.word||card.targetEnglish); }
function renderChips(items,cls=""){ return items?.length?`<div class="chip-row">${items.map(x=>`<span class="learn-chip ${cls}">${escapeHtml(typeof x==="string"?x:x.expression||"")}</span>`).join("")}</div>`:`<div class="meta">暂无补充内容</div>`; }
function renderLearningDetails(card,correct=true){
  const accepted=uniqueAnswers(card);
  const acceptedLines=accepted.map(a=>card.type==="cloze"?`${card.clozePrefix||""}${a}${card.clozeSuffix||""}`:a);
  const related=(card.relatedExpressions||[]).map(x=>typeof x==="string"?{expression:x,note:"近义或相关表达，使用时请注意语境。"}:x);
  const examples=card.extraExamples||[];
  return `<div class="learning-panel ${correct?"learn-correct":"learn-revealed"}">
    <div class="learning-head"><div><div class="learning-label">${correct?"回答正确 · 拓展学习":"答案解析 · 建议重新复习"}</div><div class="word-title">${escapeHtml(card.word||card.clozeAnswer||"本题表达")} <span>${escapeHtml(card.pronunciation||"")}</span></div><div class="word-meaning">${escapeHtml(card.partOfSpeech||"")} ${escapeHtml(card.meaningZh||"")}</div></div><div class="actions"><button class="btn btn-small btn-secondary" onclick="speakWordCurrent()">🔊 单词</button><button class="btn btn-small btn-secondary" onclick="speakCurrent()">🔊 例句</button></div></div>
    <div class="learning-grid">
      <div class="learn-block full"><h4>完整句子</h4><div class="learn-sentence">${escapeHtml(card.sentenceEn||card.targetEnglish||"")}</div><div class="learn-translation">${escapeHtml(card.sentenceZh||"")}</div></div>
      <div class="learn-block"><h4>详细释义</h4><p>${escapeHtml(card.definitionZh||card.meaningZh||"")}</p></div>
      <div class="learn-block"><h4>用法提醒</h4><p>${escapeHtml(card.usageNotes||"请结合语境和搭配整体记忆。")}</p></div>
      <div class="learn-block full"><h4>本题可接受的答案</h4>${acceptedLines.map((x,i)=>`<div class="accepted-line"><span>${i===0?"目标":"可选"}</span>${escapeHtml(x)}</div>`).join("")}</div>
      <div class="learn-block"><h4>常见搭配</h4>${renderChips(card.collocations||[])}</div>
      <div class="learn-block"><h4>词族</h4>${renderChips(card.wordFamily||[])}</div>
      <div class="learn-block full"><h4>相近表达与区别</h4>${related.length?related.map(x=>`<div class="related-line"><strong>${escapeHtml(x.expression||"")}</strong><span>${escapeHtml(x.note||"")}</span></div>`).join(""):`<div class="meta">暂无相近表达。注意：近义词不一定能直接替换本题答案。</div>`}</div>
      <div class="learn-block full"><h4>更多例句</h4>${examples.length?examples.map(x=>`<div class="example-line"><div>${escapeHtml(x.en||"")}</div><span>${escapeHtml(x.zh||"")}</span></div>`).join(""):`<div class="meta">暂无额外例句。</div>`}</div>
    </div>
  </div>`;
}
function hintStateHTML(s,card){
  if(s.hintStage===1) return `<div class="hint-status">🔊 已播放目标词或短语的发音。可以再尝试一次；仍不会时继续查看音标。</div>`;
  if(s.hintStage>=2) return `<div class="hint-status"><strong>音标提示：</strong> ${escapeHtml(card.pronunciation||card.answerPronunciation||"该词暂无音标，可再次播放发音")}</div>`;
  return "";
}
function hintButtonLabel(s){ if((s.hintStage||0)===0)return "🔊 发音提示"; if(s.hintStage===1)return "显示音标"; return "显示答案"; }

function ensureQuestionStates(s){if(!s.questionStates||typeof s.questionStates!=="object")s.questionStates={};return s.questionStates;}
function captureQuestionState(s,index=s.index){
  if(!s||index<0)return;
  const store=ensureQuestionStates(s);
  store[index]={attempts:s.attempts||0,hintUsed:!!s.hintUsed,hintStage:s.hintStage||0,revealed:!!s.revealed,feedback:s.feedback||"",message:s.message||"",currentInput:s.currentInput||"",lastAnswer:s.lastAnswer||"",spokenAfterSuccess:!!s.spokenAfterSuccess,elapsedMs:Math.max(0,Date.now()-(s.start||Date.now()))};
}
function loadQuestionState(s,index){
  const saved=ensureQuestionStates(s)[index];
  clearTimeout(s.advanceTimer);s.advanceTimer=null;
  if(saved){
    s.attempts=saved.attempts||0;s.hintUsed=!!saved.hintUsed;s.hintStage=saved.hintStage||0;s.revealed=!!saved.revealed;s.feedback=saved.feedback||"";s.message=saved.message||"";s.currentInput=saved.currentInput||"";s.lastAnswer=saved.lastAnswer||"";s.spokenAfterSuccess=!!saved.spokenAfterSuccess;s.start=Date.now()-(saved.elapsedMs||0);
  }else{
    s.attempts=0;s.hintUsed=false;s.hintStage=0;s.revealed=false;s.feedback="";s.message="";s.currentInput="";s.lastAnswer="";s.spokenAfterSuccess=false;s.start=Date.now();
  }
}
function canGoPrevious(s){return !!(s&&s.index>0&&ensureQuestionStates(s)[s.index-1]);}

practice=function(){
  const params=new URLSearchParams((location.hash.split("?")[1]||"")); const mode=params.get("mode")||state.ui.lastPracticeMode||"review";
  if(!practiceSession||practiceSession.mode!==mode){
    practiceSession={mode,queue:buildPracticeQueue(mode),index:0,attempts:0,hintUsed:false,hintStage:0,revealed:false,start:Date.now(),feedback:"",done:false,history:[],questionStates:{},currentInput:"",lastAnswer:"",advanceTimer:null,spokenAfterSuccess:false};
    state.ui.lastPracticeMode=mode;save();
  }
  const s=practiceSession; const card=s.queue[s.index];
  if(!card){render(shell(`<div class="card empty"><h3>当前没有可练习的卡片</h3><p>可以学习新词，或进入卡片管理添加内容。</p><div class="actions" style="justify-content:center"><a class="btn btn-primary" href="#/practice?mode=new">学习新词</a><a class="btn btn-secondary" href="#/cards/new">添加卡片</a></div></div>`,"练习","主动回忆、逐级提示与拓展解析"));return;}
  const answered=s.feedback==="success"||s.feedback==="revealed";
  const showAnswer=answered||s.revealed;
  const sentence=card.type==="cloze"?`${escapeHtml(card.clozePrefix)}<span class="blank">${showAnswer?escapeHtml(card.clozeAnswer):"________"}</span>${escapeHtml(card.clozeSuffix)}`:escapeHtml(card.sentenceZh);
  const progress=Math.round(s.index/s.queue.length*100);
  const wrongText=s.feedback==="wrong"?`<div class="feedback error"><div>${escapeHtml(s.message||"答案不正确，请再试一次。")}</div></div>`:"";
  const details=s.feedback==="success"?renderLearningDetails(card,true):s.feedback==="revealed"?renderLearningDetails(card,false):"";
  const hasPrevious=canGoPrevious(s);
  const controls=answered?`${hasPrevious?`<button class="btn btn-secondary" onclick="previousCard()">← 上一题</button>`:""}<button class="btn btn-primary" onclick="nextCard()">下一题 →</button><button class="btn btn-secondary" onclick="speakWordCurrent()">🔊 再听单词</button><button class="btn btn-secondary" onclick="speakCurrent()">🔊 再听例句</button>`:`<button class="btn btn-primary" onclick="submitPractice()">提交答案</button><button class="btn btn-secondary hint-main" onclick="useHint()">${hintButtonLabel(s)}</button><button class="btn btn-ghost" onclick="skipCard()">跳过</button>`;
  const sidePrevious=answered&&hasPrevious?`<button class="practice-side-nav practice-side-prev" type="button" onclick="previousCard()" aria-label="返回上一题" title="返回上一题"><span class="side-nav-label">← 上一题</span><small>${s.index}/${s.queue.length}</small></button>`:"";
  const sideNext=answered?`<button class="practice-side-nav practice-side-next" type="button" onclick="nextCard()" aria-label="进入下一题" title="进入下一题"><span class="side-nav-label">下一题 →</span><small>${s.index+1}/${s.queue.length}</small></button>`:"";
  render(shell(`<div class="practice-wrap">
    <div class="practice-top"><span class="meta">${s.index+1} / ${s.queue.length}</span><div class="progress"><span style="width:${progress}%"></span></div><button class="btn btn-small btn-secondary" onclick="finishPractice()">结束</button></div>
    <div class="card practice-card">
      <div class="practice-kicker">${card.type==="cloze"?"英语句子填词":"中文翻译成英文"}</div>
      ${card.type==="cloze"&&state.settings.showChineseHint?`<div class="prompt-cn">${escapeHtml(card.sentenceZh)}</div>`:""}
      <div class="sentence">${sentence}</div>
      <div class="answer-box"><input id="answerInput" class="input answer-input ${s.feedback==="success"?"correct":s.feedback==="wrong"?"wrong":""}" autocomplete="off" placeholder="${card.type==="cloze"?"输入缺失单词":"输入完整英文句子"}" value="${escapeHtml(s.lastAnswer||s.currentInput||"")}" ${answered?"disabled":""}/></div>
      ${wrongText}${!answered?hintStateHTML(s,card):""}${details}
      <div class="practice-actions">${controls}</div>
      <div class="hint-ladder"><span class="${s.hintStage>=1?"done":""}">1 发音</span><i>→</i><span class="${s.hintStage>=2?"done":""}">2 音标</span><i>→</i><span class="${s.revealed?"done":""}">3 答案</span></div>
      <div class="shortcut">Enter 提交 · Tab 逐级提示 · Esc 结束练习</div>
    </div>
  </div>${sidePrevious}${sideNext}`,"练习","先回忆，再按“发音 → 音标 → 答案”逐级获取帮助"));
  const input=document.getElementById("answerInput");if(input&&!answered){setTimeout(()=>input.focus(),30);input.addEventListener("keydown",e=>{if(e.key==="Enter"){e.preventDefault();submitPractice();}if(e.key==="Tab"){e.preventDefault();useHint();}if(e.key==="Escape"){finishPractice();}});}
};
submitPractice=function(){
  const s=practiceSession,c=currentCard(),input=document.getElementById("answerInput");if(!c||!input||!input.value.trim()||s.feedback==="success")return;
  s.attempts++;s.currentInput=input.value;const response=Date.now()-s.start;const ev=evaluate(c,input.value);
  if(ev.correct){
    s.lastAnswer=input.value;s.feedback="success";s.currentInput="";const result=reviewResult({correct:true,attempts:s.attempts,hintUsed:s.hintUsed,revealed:false,responseTime:response});
    schedule(c.id,result,response);state.reviewLogs.push({id:uid(),cardId:c.id,mode:c.type,userAnswer:input.value,normalizedAnswer:normalizeAnswer(input.value),result,isCorrect:true,attemptCount:s.attempts,hintUsed:s.hintUsed,answerRevealed:false,responseTimeMs:response,reviewedAt:nowISO()});save();practice();
    if(state.settings.autoPlayAudio&&!s.spokenAfterSuccess){s.spokenAfterSuccess=true;setTimeout(()=>speak(c.sentenceEn||c.targetEnglish||targetHintText(c)),180);}
    if(state.settings.autoAdvance){clearTimeout(s.advanceTimer);s.advanceTimer=setTimeout(()=>nextCard(),Math.max(3000,Number(state.settings.autoAdvanceDelay)||10000));}
  }else{s.feedback="wrong";s.message=ev.close?"非常接近，只差一个字符。请再检查拼写。":"答案不正确。可以继续尝试，或按顺序使用发音、音标和答案提示。";practice();}
};
useHint=function(){
  const s=practiceSession,c=currentCard();if(!s||!c||s.feedback==="success"||s.feedback==="revealed")return;const input=document.getElementById("answerInput");if(input)s.currentInput=input.value;s.hintUsed=true;
  if((s.hintStage||0)===0){s.hintStage=1;speak(targetHintText(c));practice();}
  else if(s.hintStage===1){s.hintStage=2;practice();}
  else revealAnswer();
};
revealAnswer=function(){
  const s=practiceSession,c=currentCard();if(!s||!c||s.revealed||s.feedback==="success")return;const input=document.getElementById("answerInput");if(input)s.currentInput=input.value;
  s.revealed=true;s.hintUsed=true;s.hintStage=3;s.feedback="revealed";s.lastAnswer=c.type==="cloze"?c.clozeAnswer:c.targetEnglish;const response=Date.now()-s.start;
  schedule(c.id,"again",response);state.reviewLogs.push({id:uid(),cardId:c.id,mode:c.type,userAnswer:s.currentInput||"",normalizedAnswer:normalizeAnswer(s.currentInput||""),result:"again",isCorrect:false,attemptCount:s.attempts,hintUsed:true,answerRevealed:true,responseTimeMs:response,reviewedAt:nowISO()});save();practice();
  if(state.settings.autoPlayAudio)setTimeout(()=>speak(c.sentenceEn||c.targetEnglish||targetHintText(c)),180);
};
skipCard=function(){const s=practiceSession,c=currentCard();if(!s||!c)return;if(s.feedback==="success"||s.feedback==="revealed"){nextCard();return;}const response=Date.now()-s.start;schedule(c.id,"again",response);state.reviewLogs.push({id:uid(),cardId:c.id,mode:c.type,userAnswer:s.currentInput||"",normalizedAnswer:normalizeAnswer(s.currentInput||""),result:"again",isCorrect:false,attemptCount:s.attempts,hintUsed:s.hintUsed,answerRevealed:false,responseTimeMs:response,reviewedAt:nowISO()});save();nextCard();};
nextCard=function(){const s=practiceSession;if(!s)return;captureQuestionState(s);clearTimeout(s.advanceTimer);const nextIndex=s.index+1;if(nextIndex>=s.queue.length){finishPractice(true);return;}s.index=nextIndex;loadQuestionState(s,nextIndex);practice();};
previousCard=function(){const s=practiceSession;if(!s||!canGoPrevious(s))return;captureQuestionState(s);clearTimeout(s.advanceTimer);s.index=Math.max(0,s.index-1);loadQuestionState(s,s.index);practice();};
speakWordCurrent=function(){const c=currentCard();if(c)speak(targetHintText(c));};

